const config = $('Read Config').first().json;

if (!config.version || config.version !== 3) {
  throw new Error('CONFIG_VERSION_MISMATCH: Expected version 3, got ' + config.version);
}

if (!Array.isArray(config.categories) || config.categories.length === 0) {
  throw new Error('NO_CATEGORIES: config.json has no categories');
}

const enabled = config.categories.filter(c => c.enabled);
if (enabled.length === 0) {
  throw new Error('NO_CATEGORY_ENABLED: All categories are disabled');
}

return { json: { valid: true, categoryCount: config.categories.length, enabledCount: enabled.length } };

const config = $('Read Config').first().json;
const stateRaw = $('Download State').first().json;

// Parse state if it's a string
let state = stateRaw;
if (typeof stateRaw === 'string') {
  try { state = JSON.parse(stateRaw); } catch {
    state = { cycleIndex: 0, adultSubCycleIndex: 0, categorySkipCount: {}, lastRun: null };
  }
}

// Get enabled categories in rotation order
const enabledCategories = (config.rotation.order || [])
  .map(id => config.categories.find(c => c.id === id))
  .filter(c => c && c.enabled);

if (enabledCategories.length === 0) {
  throw new Error('NO_CATEGORY_ENABLED');
}

// Index-based rotation (NOT modulo on filtered array)
const nextIndex = (state.cycleIndex + 1) % enabledCategories.length;
const category = enabledCategories[nextIndex];

const result = {
  selectedCategoryId: category.id,
  selectedCategory: category,
  nextCycleIndex: nextIndex,
  stateUpdates: {
    cycleIndex: nextIndex,
    lastRun: new Date().toISOString()
  }
};

// Adult sub-rotation
if (category.type === 'adult') {
  const enabledSubTypes = (category.subTypes || []).filter(st => st.enabled);
  if (enabledSubTypes.length > 0) {
    const subIndex = (state.adultSubCycleIndex || 0) % enabledSubTypes.length;
    result.selectedSubType = enabledSubTypes[subIndex];
    result.stateUpdates.adultSubCycleIndex = (state.adultSubCycleIndex + 1) % enabledSubTypes.length;
  } else {
    result.selectedSubType = null;
  }
} else {
  result.selectedSubType = null;
}

// Skip threshold check
const skipCount = (state.categorySkipCount || {})[category.id] || 0;
result.categorySkipCount = skipCount;
result.shouldSkip = skipCount >= 3;

return result;

const rotation = $('Calculate Rotation').first().json;
const stateRaw = $('Download State').first().json;

let state = stateRaw;
if (typeof stateRaw === 'string') {
  try { state = JSON.parse(stateRaw); } catch {
    state = { cycleIndex: 0, adultSubCycleIndex: 0, categorySkipCount: {}, lastRun: null };
  }
}

// Merge categorySkipCount — reset selected category on successful run
const newSkipCount = { ...(state.categorySkipCount || {}) };
newSkipCount[rotation.selectedCategoryId] = 0;

const newState = {
  cycleIndex: rotation.nextCycleIndex,
  adultSubCycleIndex: rotation.stateUpdates.adultSubCycleIndex ?? state.adultSubCycleIndex ?? 0,
  categorySkipCount: newSkipCount,
  lastRun: new Date().toISOString()
};

return { json: newState };

